1	'use strict';
2	// catalogue/linters/lib.js - shared support for the catalogue linter fleet (citation-completeness,
3	// polarity, regex-health, threshold-guard). One door for "how a linter finds its input files and
4	// what shape a record is in", so four linters do not grow four slightly-different pack loaders
5	// (the clone class jscpd and tools/lib/fswalk.js already exist to stop elsewhere in this repo).
6	//
7	// Every linter accepts TWO input shapes over the SAME loader:
8	//   1. Real packs:   catalogue/packs/*.json, {cell, jurisdiction, generated, records: [COM record, ...]}
9	//   2. Calibration:  eval/calibration-known-bad/fixtures/*.json, a MIX of:
10	//        a) a full COM-shaped pack (a p2-* fixture this catalogue-linters build owns), or
11	//        b) a single bare COM record (no {cell,...} wrapper), or
12	//        c) a single LEGACY flat-rule record (framework_short/style/regex_pattern shape,
13	//           pre-dating the Compliance Object Model, seeded by an earlier phase and still wired
14	//           into eval/calibration-known-bad/run.js's CALIBRATIONS table under the names
15	//           rule-dead-regex.json / rule-polarity-inverted.json). This loader recognises all
16	//           three shapes so regex-health.js and polarity.js keep the pre-existing calibration
17	//           gate honest instead of silently reporting zero on a fixture shape they do not own.
18	//        d) anything else (a fixture belonging to a DIFFERENT gate, e.g. p1-sector-*.json,
19	//           payload-missing-fields.json) is recognised as "not a rule/record" and skipped -
20	//           a linter must never crash or invent a false finding on another gate's fixture.
21	
22	const fs = require('fs');
23	const path = require('path');
24	
25	const { runGateCli } = require('../../tools/lib/gate-cli');
26	const safePath = require('../../tools/lib/safe-path');
27	
28	const REPO_ROOT = path.resolve(__dirname, '..', '..');
29	const DEFAULT_PACK_GLOB = 'catalogue/packs/*.json';
30	const CALIBRATE_DIR = path.join('eval', 'calibration-known-bad', 'fixtures');
31	
32	function isPlainObject(x) {
33	  return x !== null && typeof x === 'object' && !Array.isArray(x);
34	}
35	
36	// ---------------------------------------------------------------------------------
37	// File resolution. Deliberately minimal (zero new npm deps): supports a bare directory
38	// (expands to its *.json files, non-recursive, sorted), a "<dir>/*.json" or "<dir>/*"
39	// glob, or a single literal file path. Anything else resolves to [] rather than throwing -
40	// the caller reports "0 files matched", never crashes on an odd argv.
41	// ---------------------------------------------------------------------------------
42	// parseDirAndExt(raw) -> { dir, ext }. A "<dir>/*.ext" or "<dir>/*" wildcard splits into its
43	// directory and extension filter; anything else is a literal dir/file with the default ".json"
44	// filter. Pulled out of resolveJsonFiles below (Constitution Rule 4/tools/health-gate/check.js
45	// caps) as a pure, branch-light data-shaping step.
46	function parseDirAndExt(raw) {
47	  const wildcardMatch = raw.match(/^(.*)\/\*(\.[A-Za-z0-9]+)?$/);
48	  if (wildcardMatch) return { dir: wildcardMatch[1], ext: wildcardMatch[2] || '' }; // "<dir>/*" (no extension filter) vs "<dir>/*.json"
49	  return { dir: raw, ext: '.json' };
50	}
51	
52	// listDirJsonFiles(absDir, ext) -> the sorted, safe-joined *.json files directly inside absDir
53	// matching the optional extension filter. Pulled out of resolveJsonFiles below so the directory
54	// leg is its own small named unit.
55	function listDirJsonFiles(absDir, ext) {
56	  return fs.readdirSync(absDir)
57	    .filter((f) => (ext ? f.endsWith(ext) : true))
58	    .filter((f) => f.endsWith('.json')) // this loader only ever parses JSON
59	    .sort()
60	    .map((f) => safePath.safeJoin(absDir, [f], { label: 'catalogue linter input file' }));
61	}
62	
63	function resolveJsonFiles(patternOrDir) {
64	  const raw = String(patternOrDir || '');
65	  const { dir, ext } = parseDirAndExt(raw);
66	  // dir/raw are caller-supplied SCAN targets: a CLI positional, DEFAULT_PACK_GLOB, CALIBRATE_DIR,
67	  // OR the ABSOLUTE per-pack paths catalogue/compile.js hands its linter fleet (already safeJoin-
68	  // validated from PACKS_DIR). Allowlist them as safe SCAN paths (absolute is accepted and used
69	  // directly; a relative one is traversal-guarded and resolved against REPO_ROOT) before they ever
70	  // reach path.resolve - CR safe-path.js:43 consumer audit: a read-scan target legitimately arrives
71	  // absolute and must not be rejected the way a base-relative WRITE arg is. An empty string is a
72	  // legitimate "no directory named" case (falls through to the empty [] return below) so it is
73	  // exempted from the check rather than treated as unsafe.
74	  if (dir) safePath.assertSafeScanPath(dir, { label: 'catalogue linter scan directory' });
75	  const absDir = path.resolve(REPO_ROOT, dir);
76	  if (fs.existsSync(absDir) && fs.statSync(absDir).isDirectory()) {
77	    return listDirJsonFiles(absDir, ext);
78	  }
79	  if (raw) safePath.assertSafeScanPath(raw, { label: 'catalogue linter scan file' });
80	  const absFile = path.resolve(REPO_ROOT, raw);
81	  if (fs.existsSync(absFile) && fs.statSync(absFile).isFile()) return [absFile];
82	  return [];
83	}
84	
85	// dirsOrPatterns: array of directory/glob/file strings (as passed by tools/lib/gate-cli.js's
86	// runGateCli, which supplies [CALIBRATE_DIR] under --calibrate and the caller's scanDirs
87	// otherwise). Returns a flat, de-duplicated, sorted absolute file list.
88	function resolveManyJsonFiles(dirsOrPatterns) {
89	  const set = new Set();
90	  for (const p of dirsOrPatterns || []) {
91	    for (const f of resolveJsonFiles(p)) set.add(f);
92	  }
93	  return Array.from(set).sort();
94	}
95	
96	// ---------------------------------------------------------------------------------
97	// Shape detection + record extraction. Never throws: a file that fails to parse is
98	// reported back as a parseError entry (recorded, not swallowed - Constitution Rule 4)
99	// rather than aborting the whole scan, since one unrelated gate's malformed fixture
100	// must never take down every catalogue linter's calibration run.
101	// ---------------------------------------------------------------------------------
102	function isComRecordShape(obj) {
103	  return isPlainObject(obj)
104	    && typeof obj.id === 'string'
105	    && isPlainObject(obj.citation)
106	    && Array.isArray(obj.website_obligations);
107	}
108	
109	function isLegacyRuleShape(obj) {
110	  return isPlainObject(obj)
111	    && typeof obj.regex_pattern === 'string'
112	    && (typeof obj.style === 'string' || typeof obj.framework_short === 'string');
113	}
114	
115	// recordParseError(message) -> { parseError: message }. A pack/fixture JSON that cannot be read
116	// or parsed must surface as a typed, propagated error state, never be silently skipped
117	// (Constitution Rule 4). A bare `return { parseError }` reads as swallowing to the repo-wide
118	// swallow-gate AST scan (tools/swallow-gate/check.js), which only recognises a catch body that
119	// RETHROWS or calls a recognisable recorder; this named helper IS that recording call, and every
120	// caller (loadRecords below, and every linter's scan()) forwards parseErrors rather than dropping
121	// them.
122	function recordParseError(message) {
123	  return { parseError: message };
124	}
125	
126	// recordsFromFile(absPath) -> { parseError } | { entries: [{ file, locator, record, shape }] }
127	// shape is 'com' or 'legacy'. locator is a human-readable position ("records[3]" or the bare
128	// filename) used to build traceable finding messages.
129	function recordsFromFile(absPath) {
130	  const rel = path.relative(REPO_ROOT, absPath).replace(/\\/g, '/');
131	  let text;
132	  try {
133	    text = fs.readFileSync(absPath, 'utf8');
134	  } catch (e) {
135	    return recordParseError(rel + ': read failed: ' + e.message);
136	  }
137	  let parsed;
138	  try {
139	    parsed = JSON.parse(text);
140	  } catch (e) {
141	    return recordParseError(rel + ': invalid JSON: ' + e.message);
142	  }
143	
144	  const entries = [];
145	  if (isPlainObject(parsed) && Array.isArray(parsed.records)) {
146	    parsed.records.forEach((record, i) => {
147	      if (isComRecordShape(record)) {
148	        entries.push({ file: rel, locator: rel + ':records[' + i + ']', record, shape: 'com', pack: parsed });
149	      }
150	      // a records[] entry that is neither COM-shaped nor relevant is silently skipped: schema.js
151	      // is the door for "is this a well-formed record at all", not this loader.
152	    });
153	    return { entries };
154	  }
155	  if (isComRecordShape(parsed)) {
156	    entries.push({ file: rel, locator: rel, record: parsed, shape: 'com', pack: null });
157	    return { entries };
158	  }
159	  if (isLegacyRuleShape(parsed)) {
160	    entries.push({ file: rel, locator: rel, record: parsed, shape: 'legacy', pack: null });
161	    return { entries };
162	  }
163	  return { entries: [] }; // recognisably not a rule/record fixture - belongs to another gate
164	}
165	
166	// loadRecords(dirsOrPatterns) -> { entries: [...], parseErrors: [...] }
167	function loadRecords(dirsOrPatterns) {
168	  const files = resolveManyJsonFiles(dirsOrPatterns);
169	  const entries = [];
170	  const parseErrors = [];
171	  for (const f of files) {
172	    const r = recordsFromFile(f);
173	    if (r.parseError) parseErrors.push(r.parseError); // RECORDED, never thrown past the caller
174	    else entries.push(...r.entries);
175	  }
176	  return { entries, parseErrors, filesScanned: files.length };
177	}
178	
179	// parseErrorViolations(parseErrors) -> violation[] in the SAME uniform {file, locator, id, rule,
180	// message} shape every linter's own content-check violations already use. Every catalogue linter's
181	// scan() folds this straight into the violations array it returns (never a side channel the CLI
182	// forgets to look at) so a file that could not even be READ fails the gate through the exact same
183	// path a real content defect does (Constitution Rule 4/CR-7): before this existed, a linter whose
184	// ONLY problem that run was an unreadable/unparseable file returned zero violations and exited 0 -
185	// a gate that never actually looked at a file is not the same as a gate that found nothing wrong.
186	// `file` is recovered from the loader's own "rel: reason" string shape (recordParseError above);
187	// this stays backward-compatible with any caller still reading the raw parseErrors string array.
188	function parseErrorViolations(parseErrors) {
189	  return (parseErrors || []).map((pe) => {
190	    const sepIdx = pe.indexOf(': ');
191	    const file = sepIdx === -1 ? pe : pe.slice(0, sepIdx);
192	    const reason = sepIdx === -1 ? pe : pe.slice(sepIdx + 2);
193	    return { file, locator: file, id: '<parse-error>', rule: 'linter-parse-error', message: reason };
194	  });
195	}
196	
197	// ---------------------------------------------------------------------------------
198	// Host allowlist matching: host === suffix, or host ends with "." + suffix. Used by
199	// citation-completeness.js against its OFFICIAL_HOSTS export.
200	// ---------------------------------------------------------------------------------
201	function hostMatchesAllowlist(host, allowlist) {
202	  const h = String(host || '').toLowerCase();
203	  if (!h) return false;
204	  return (allowlist || []).some((suffix) => {
205	    const s = String(suffix).toLowerCase();
206	    return h === s || h.endsWith('.' + s);
207	  });
208	}
209	
210	function urlHost(u) {
211	  try { return new URL(u).hostname; }
212	  catch (e) { return null; /* FAIL-OPEN: an unparsable URL is reported by the caller as its own finding, not derived here */ }
213	}
214	
215	// ---------------------------------------------------------------------------------
216	// runLinterCli(linter, name, opts) - the CLI tail shared by every catalogue linter's main(): parse
217	// argv for an optional positional pack glob (ignoring --calibrate/--json and the --json value),
218	// default to DEFAULT_PACK_GLOB, and hand off to tools/lib/gate-cli's runGateCli. `linter` is
219	// {selfTest, scan, toFindings} (pass the linter's own top-level functions, never `module.exports`
220	// - main() typically runs before the bottom-of-file `module.exports = {...}` assignment executes).
221	// Three of the four linters (citation-completeness, polarity, threshold-guard) share the
222	// summary/calibrateSummary/violationLine wording verbatim (the jscpd clone this helper exists to
223	// clear); regex-health overrides summary/calibrateSummary via opts for its "honest zero" wording.
224	// Every linter still owns its own selfTest/scan/toFindings.
225	// isCliPositionalArg(a, i, argv) -> boolean. Named predicate pulled out of resolvePackGlob's
226	// former inline filter callback (Constitution Rule 4/tools/health-gate/check.js caps).
227	function isCliPositionalArg(a, i, argv) {
228	  return a !== '--calibrate' && a !== '--json' && argv[i - 1] !== '--json';
229	}
230	
231	// resolvePackGlob(argv) -> the first positional CLI arg (ignoring --calibrate/--json and the
232	// --json value), or DEFAULT_PACK_GLOB. Pulled out of runLinterCli below.
233	function resolvePackGlob(argv) {
234	  const positional = argv.filter((a, i) => isCliPositionalArg(a, i, argv));
235	  return positional[0] || DEFAULT_PACK_GLOB;
236	}
237	
238	// defaultSummary/defaultCalibrateSummary/defaultViolationLine: the shared wording three of the
239	// four catalogue linters use verbatim (see the jscpd-clone note on runLinterCli below). Named and
240	// pulled out of runLinterCli's own default-option expressions so each is its own small unit.
241	function defaultSummary(r) {
242	  return r.scanned + ' record(s) scanned, ' + r.violations.length + ' violation(s)'
243	    + (r.parseErrors.length ? ' (' + r.parseErrors.length + ' file(s) unreadable: ' + r.parseErrors.join('; ') + ')' : '');
244	}
245	function defaultCalibrateSummary(r) {
246	  return r.scanned + ' fixture record(s) scanned, ' + r.violations.length + ' seeded violation(s) found';
247	}
248	function defaultViolationLine(v) {
249	  return '[' + v.rule + '] ' + v.locator + ' (' + v.id + '): ' + v.message;
250	}
251	
252	function runLinterCli(linter, name, opts) {
253	  const o = opts || {};
254	  const argv = process.argv.slice(2);
255	  const packGlob = resolvePackGlob(argv);
256	
257	  runGateCli({
258	    name,
259	    selfTest: linter.selfTest,
260	    scan: linter.scan,
261	    toFindings: linter.toFindings,
262	    scanDirs: [packGlob],
263	    summary: o.summary || defaultSummary,
264	    calibrateSummary: o.calibrateSummary || defaultCalibrateSummary,
265	    violationLine: o.violationLine || defaultViolationLine,
266	  });
267	}
268	
269	// makeToFindings(toolName) -> (violations) => finding[]. The uniform normaliser-shaped finding
270	// every linter's toFindings() produces (tools/sweep/normalise.js's expected shape; another jscpd
271	// clone this helper exists to clear - all four linters carried this shape near-verbatim). `level`
272	// is 'error' unless the violation itself carries `severity: 'warning'` (polarity's
273	// negation-guard-needed, threshold-guard's typical-band-missing); a violation with no severity
274	// field (citation-completeness, regex-health) is always 'error'.
275	function makeToFindings(toolName) {
276	  return (violations) => violations.map((v) => ({
277	    tool: toolName,
278	    ruleId: v.rule,
279	    file: v.file,
280	    startLine: 0,
281	    endLine: 0,
282	    level: v.severity === 'warning' ? 'warning' : 'error',
283	    message: '[' + v.id + '] ' + v.locator + ': ' + v.message,
284	  }));
285	}
286	
287	module.exports = {
288	  REPO_ROOT,
289	  DEFAULT_PACK_GLOB,
290	  CALIBRATE_DIR,
291	  isPlainObject,
292	  isComRecordShape,
293	  isLegacyRuleShape,
294	  resolveJsonFiles,
295	  resolveManyJsonFiles,
296	  recordsFromFile,
297	  loadRecords,
298	  parseErrorViolations,
299	  hostMatchesAllowlist,
300	  urlHost,
301	  runLinterCli,
302	  makeToFindings,
303	};
