2	'use strict';
3	/**
4	 * FACTS-ABSTAIN: the unreachable/empty-bundle abstention gate.
5	 *
6	 * Calibration id: p1-unreachable-bundle-abstain (eval/calibration-known-bad/run.js), fixture
7	 * eval/calibration-known-bad/fixtures/p1-reference-fixtures-unreachable-bundle.json.
8	 *
9	 * A bot-walled page (caution.md C-038: jarir.com, empty corpus) or an unrendered SPA shell
10	 * (C-032: royalparkpartners.com, zero visible text) must never be asserted against: every facts
11	 * module fed such a bundle must ABSTAIN on every fact. This checker runs facts/identity.js,
12	 * facts/jurisdiction.js and facts/sector.js over every bundle it is given that LOOKS unreachable
13	 * (bundle.unreachable === true, or a non-empty pages[] whose visible text is entirely blank) and
14	 * reports a finding for every non-abstain emission it sees - the seeded disease this gate exists
15	 * to catch (facts/identity.js's rung-6 domain-stem fallback is "always clean" for a genuinely
16	 * reachable site with only a weak signal, but it fires just as readily on a page nobody ever
17	 * actually read, which is exactly the class this gate polices).
18	 *
19	 * Modes (the tools/lib/gate-cli.js dialect; see tools/swallow-gate/check.js for the same contract):
20	 *   node tools/facts-abstain/check.js <bundle.json> [<bundle.json>|<dir> ...]   scan real bundle
21	 *                                     file(s), exit 1 on any non-abstain emission
22	 *   node tools/facts-abstain/check.js --calibrate    scan eval/calibration-known-bad/fixtures/ and
23	 *                                     REQUIRE the seeded unreachable bundles to be caught
24	 *   ... --json <path>   also write findings JSON for the sweep normaliser
25	 */
26	const fs = require('fs');
27	const path = require('path');
28	
29	const { runGateCli, ROOT } = require('../lib/gate-cli');
30	const safePath = require('../lib/safe-path');
31	const identity = require('../../facts/identity.js');
32	const jurisdiction = require('../../facts/jurisdiction.js');
33	const sector = require('../../facts/sector.js');
34	
35	// looksUnreachable(bundle) -> true when this gate's abstention doctrine applies: the bundle says
36	// so itself, or a fetched page carries zero visible text ANYWHERE this gate is willing to call
37	// "content" (the SPA-shell class). CR-40 (CodeRabbit PR #3, tools/facts-abstain/check.js#L39-L41):
38	// this must include corpus.footerText - a page whose body text is blank but whose CAPTURED footer
39	// carries real content (company number, registered office, etc - exactly the surface
40	// facts/identity.js's own footer-text detection reads) is NOT the bot-walled/SPA-shell class this
41	// gate exists to police; treating it as unreachable would wrongly force abstention on a genuinely
42	// readable page.
43	// corpusVisibleText(bundle) -> { pageCount, text }: the count of captured pages and ALL the visible
44	// text this gate is willing to call "content" (every page's text PLUS corpus.footerText, per CR-40),
45	// trimmed. Extracted so looksUnreachable stays a thin decision under the caps.
46	function corpusVisibleText(bundle) {
47	  const corpus = (bundle && bundle.corpus) || {};
48	  const pages = Array.isArray(corpus.pages) ? corpus.pages : [];
49	  const pageText = pages.map((p) => (p && typeof p.text === 'string' ? p.text : '')).join('');
50	  const footerText = typeof corpus.footerText === 'string' ? corpus.footerText : '';
51	  return { pageCount: pages.length, text: (pageText + footerText).trim() };
52	}
53	
54	function looksUnreachable(bundle) {
55	  if (!bundle || typeof bundle !== 'object') return false;
56	  if (bundle.unreachable === true) return true;
57	  const { pageCount, text } = corpusVisibleText(bundle);
58	  return pageCount > 0 && text.length === 0;
59	}
60	
61	// bundlesIn(parsed) -> [bundle, ...]. Accepts either the calibration fixture's {bundles:[...]}
62	// wrapper or a single bare EvidenceBundle (the "loads a bundle JSON given as argv" shape).
63	function bundlesIn(parsed) {
64	  if (!parsed || typeof parsed !== 'object') return [];
65	  if (Array.isArray(parsed.bundles)) return parsed.bundles;
66	  if (parsed.corpus) return [parsed];
67	  return [];
68	}
69	
70	// REAL_RESOLVERS: the production facts modules this gate polices in every real scan (CLI runs,
71	// the eval/calibration-known-bad/ fixture run, and the "real-module" test in check.test.js). The
72	// ONLY door through which checkBundle talks to facts/identity.js, facts/jurisdiction.js and
73	// facts/sector.js - selfTest below never imports this constant, keeping the two concerns (does the
74	// GATE'S OWN LOGIC catch a non-abstain emission; does the REAL production code currently abstain)
75	// structurally separate (CR-42).
76	const REAL_RESOLVERS = {
77	  resolveIdentity: (bundle) => identity.resolveIdentity(bundle),
78	  resolveJurisdiction: (bundle) => jurisdiction.resolveJurisdiction(bundle),
79	  resolveSector: (bundle) => sector.resolveSector(bundle),
80	};
81	
82	// checkBundle(bundle, source, resolvers = REAL_RESOLVERS) -> finding[]. Never throws: a facts
83	// module throwing on an unreachable bundle IS itself a finding, not a crash that hides the disease
84	// this gate exists to report (Constitution Rule 4). `resolvers` is an injectable {resolveIdentity,
85	// resolveJurisdiction, resolveSector} triple (CR-42): production code and the calibration fixture
86	// run always use REAL_RESOLVERS; selfTest below injects DELIBERATELY FAULTY stubs instead, so this
87	// gate's self-test proves its OWN detection logic, not a currently-live production bug that a
88	// future fix could silently make disappear.
89	// checkIdentity/checkJurisdiction/checkSector: one resolver each, split out of checkBundle so no single
