56	// diffArrays(golden, fresh, prefix, out) -> the array-shaped branch of deepDiff: a length
57	// mismatch is itself a diff, and every shared index is compared recursively. Unchanged from the
58	// original inline block.
59	function diffArrays(golden, fresh, prefix, out) {
