230	// Two checker dialects are accepted:
231	//   a) stdout dialect: `--calibrate` prints {"checker":"...","findings":[...]} to stdout, exit 0.
232	//   b) gate-cli dialect (tools/lib/gate-cli.js): `--calibrate --json <path>` writes a findings
233	//      ARRAY to <path>, prints human text to stdout, and exits 1 when zero violations were
234	//      found. A non-zero exit is therefore NOT a runner error here: we still read the JSON
235	//      file and let this runner judge the (possibly empty) findings list.
236	// runCalibrateProcess(checkerPath, jsonOut) -> stdout from spawning the checker's --calibrate
237	// contract, having already validated its exit status against the two runner-judged states.
238	// The --calibrate contract has exactly two runner-judged statuses: 0 (checker found violations) and
239	// 1 (checker found ZERO on its fixtures - the caller then FAILs that calibration from the empty
240	// findings list). Exit 2 means the checker's OWN self-test failed: it is a broken tool and can
241	// NEVER earn a PASS, no matter what findings it managed to write. A broken self-test masked by
242	// parsed findings is the unearned-zero disease (Constitution Rule 4), so reject it unconditionally.
243	function runCalibrateProcess(checkerPath, jsonOut) {
244	  let stdout = '';
245	  let status = 0;
246	  try {
247	    stdout = execFileSync(process.execPath, [checkerPath, '--calibrate', '--json', jsonOut], {
248	      cwd: REPO_ROOT,
249	      encoding: 'utf8',
250	      timeout: 120000,
251	    });
252	  } catch (e) {
253	    // gate-cli exits 1 on zero calibration findings and 2 on a failed self-test. Keep the
254	    // stdout we got; if the checker wrote no JSON file either, the throw below reports it.
255	    stdout = (e.stdout || '') + '';
256	    status = (typeof e.status === 'number') ? e.status : 2;
257	  }
258	  if (status === 2) {
259	    throw new Error('checker self-test FAILED (exit 2): it cannot see the class it exists to catch, so its calibration result is void and cannot be masked by any parsed findings');
260	  }
261	  if (status !== 0 && status !== 1) {
262	    throw new Error('checker exited with undocumented --calibrate status ' + status + ' (expected 0 = findings, 1 = zero-findings, 2 = broken self-test)');
263	  }
264	  return stdout;
265	}
