3	// catalogue/linters/regex-health.js - the earn-your-zero regex gate (caution.md C-050).
4	//
5	// 27 stored trigger patterns had corrupted escapes (\b -> b, \s -> s) and dead-in-production
6	// patterns like dpo[@\s] compiled, ran, and matched nothing forever. The fix that class needs
7	// is not "does it compile" (a broken pattern still compiles) but "does it match the thing it was
8	// written to catch": every regex-bearing field must carry a positive_example string the SAME
9	// pattern actually matches, proved by running the pattern, not by reading it.
10	//
11	// The Compliance Object Model (COM) records in catalogue/packs/*.json carry NO regex fields
12	// today (website_obligations describe duties in prose; detection is a future migration step -
13	// caution.md's own historical bugs lived in the LEGACY per-rule regex catalogue this repo is
14	// replacing). This linter is written for that migration ahead of time: it recursively walks
15	// every record looking for a field literally named pattern / regex / regex_pattern / detect /
16	// detection / check_spec whose value is a STRING (a container object under one of those names is
17	// walked into, not itself treated as a pattern). For each one found:
18	//   - the pattern must COMPILE (new RegExp(pattern, flags))
19	//   - the record (or the field's own sibling object) must carry a positive_example string
20	//   - pattern.test(positive_example) must be true
21	// Zero regex-bearing fields in the scanned input is reported HONESTLY as "0 patterns (nothing to
22	// check)" and exits 0 - a gate with nothing to check is not the same as a gate that let something
23	// through, and this file must never manufacture a violation to look busy.
24	const lib = require('./lib');
25	
26	const REGEX_FIELD_KEY_RX = /^(pattern|regex|regex_pattern|detect|detection|check_spec)$/i;
27	
28	// isPatternFieldEntry(key, value) -> boolean. Named predicate pulled out of walkForPatternFields'
29	// own if TEST (the multi-operator test now lives in a RETURN, not a test position; Constitution
30	// Rule 4/tools/health-gate/check.js caps).
31	function isPatternFieldEntry(key, value) {
32	  return REGEX_FIELD_KEY_RX.test(key) && typeof value === 'string' && value.length > 0;
33	}
34	
35	// flagsFor(node) -> the regex flags a pattern-bearing node declares, or the 'i' default.
36	function flagsFor(node) {
37	  return typeof node.flags === 'string' ? node.flags : 'i';
38	}
39	
40	// walkForPatternFields(node, pathStr) -> [{ path, pattern, flags, parent }]
41	// parent is the object that DIRECTLY holds the pattern field, so a sibling positive_example can
42	// be looked up next to it.
43	function walkForPatternFields(node, pathStr, out) {
44	  if (node === null || typeof node !== 'object') return out;
45	  if (Array.isArray(node)) {
46	    node.forEach((v, i) => walkForPatternFields(v, pathStr + '[' + i + ']', out));
47	    return out;
48	  }
49	  for (const key of Object.keys(node)) {
50	    const value = node[key];
51	    const childPath = pathStr + '.' + key;
52	    if (isPatternFieldEntry(key, value)) {
53	      out.push({ path: childPath, pattern: value, flags: flagsFor(node), parent: node });
54	    }
55	    walkForPatternFields(value, childPath, out);
56	  }
57	  return out;
58	}
