60	// recordFinding(findings, entry) - the catch below is the linter's own job, not a swallow: a
61	// pattern that fails to compile IS a finding, never a skip. A bare `findings.push(...)` inside a
62	// catch reads as swallowing to the repo-wide swallow-gate AST scan (tools/swallow-gate/check.js),
63	// which only recognises a catch body that RETHROWS or calls a recognisable recorder; this named
64	// helper IS that recording call.
65	function recordFinding(findings, entry) {
66	  findings.push(entry);
67	}
68	
69	// MAX_PATTERN_LENGTH (SCAN-7): a catalogue-supplied pattern longer than this is refused BEFORE it
70	// ever reaches `new RegExp(...)` - a length cap is real, cheap defence-in-depth against a
71	// pathologically long/adversarial pattern string reaching regex compilation, independent of the
72	// try/catch immediately below.
73	const MAX_PATTERN_LENGTH = 2000;
74	
75	// recordId(record) -> the record's own id, or its legacy framework_short, or '<no id>'. Pulled out
76	// of checkRecord's former nested ternary (Constitution Rule 4/tools/health-gate/check.js caps).
77	function recordId(record) {
78	  if (typeof record.id === 'string') return record.id;
79	  if (typeof record.framework_short === 'string') return record.framework_short;
80	  return '<no id>';
81	}
82	
83	// computePositiveExample(f, record) -> the positive_example string to prove a pattern against
84	// (sibling-first, then record-level, then null). Pulled out of checkOneField below so the former
85	// OR-chain lives in a small named unit of its own.
86	function computePositiveExample(f, record) {
87	  if (typeof f.parent.positive_example === 'string' && f.parent.positive_example) return f.parent.positive_example;
88	  if (typeof record.positive_example === 'string' && record.positive_example) return record.positive_example;
89	  return null;
