92	// checkOneField(f, ctx) - one regex-bearing field's full length/compile/example/match check.
93	// Pulled out of checkRecord's former for-loop body (Constitution Rule 4/tools/health-gate/
94	// check.js caps: the loop body carried this file's whole per-field decision tree). ctx bundles
95	// {record, id, locator, findings} (Constitution Rule 4/tools/health-gate/check.js ARGS cap: keeps
96	// this helper at two formal params instead of five). Pushes onto ctx.findings directly (mirrors
97	// the original loop's early `continue` exits as early `return`s, since there was never anything
98	// after them in the loop body).
99	function checkOneField(f, ctx) {
100	  const { record, id, locator, findings } = ctx;
101	  if (f.pattern.length > MAX_PATTERN_LENGTH) {
102	    recordFinding(findings, { locator, id, rule: 'regex-health/pattern-too-long', level: 'error', message: f.path + ': pattern is ' + f.pattern.length + ' chars, exceeds the ' + MAX_PATTERN_LENGTH + '-char cap this linter enforces before compiling a catalogue-supplied pattern (ReDoS defence-in-depth) - shorten the pattern' });
103	    return;
104	  }
105	  let compiled = null;
106	  try {
107	    // By design: this linter compiles catalogue patterns to prove they are alive; input length-capped, failure is itself a finding.
108	    compiled = new RegExp(f.pattern, f.flags);
109	  } catch (e) {
110	    recordFinding(findings, { locator, id, rule: 'regex-health/pattern-does-not-compile', level: 'error', message: f.path + ': ' + JSON.stringify(f.pattern) + ' fails to compile: ' + e.message });
111	    return;
112	  }
113	  const positiveExample = computePositiveExample(f, record);
114	  if (!positiveExample) {
115	    findings.push({ locator, id, rule: 'regex-no-positive-example', message: f.path + ': ' + JSON.stringify(f.pattern) + ' has no positive_example to prove it against (earn-your-zero: an unproven pattern is a dead pattern until shown otherwise)' });
116	    return;
117	  }
118	  if (!compiled.test(positiveExample)) {
119	    findings.push({ locator, id, rule: 'regex-dead-pattern', message: f.path + ': ' + JSON.stringify(f.pattern) + ' does NOT match its own positive_example ' + JSON.stringify(positiveExample) + ' (the over-escaped/C-050 dead-regex class)' });
120	  }
121	}
