123	// checkRecord(record, locator) -> finding[]
124	function checkRecord(record, locator) {
125	  const id = recordId(record);
126	  const fields = walkForPatternFields(record, 'record', []);
127	  const findings = [];
128	  const ctx = { record, id, locator, findings };
129	  for (const f of fields) checkOneField(f, ctx);
130	  return { findings, patternCount: fields.length };
131	}
