133	function scan(dirsOrPatterns) {
134	  const { entries, parseErrors } = lib.loadRecords(dirsOrPatterns);
135	  const violations = [];
136	  let patternCount = 0;
137	  for (const entry of entries) {
138	    const { findings, patternCount: n } = checkRecord(entry.record, entry.locator);
139	    patternCount += n;
140	    for (const f of findings) violations.push({ file: entry.file, ...f });
141	  }
142	  // CR-7: an unreadable/unparseable file fails the gate through the same violations array a real
143	  // regex-health defect uses.
