148	function selfTest() {
149	  const dead = { id: 'CAL_SELFTEST_DEAD', detection: { pattern: 'dpo[@\\\\s]', positive_example: 'our dpo contact form is on this page' } };
150	  const noExample = { id: 'CAL_SELFTEST_NOEX', regex_pattern: 'dpo@' };
151	  const good = { id: 'CAL_SELFTEST_GOOD', detection: { pattern: 'dpo\\s*@', positive_example: 'email dpo@example.com for data requests' } };
152	  const zero = { id: 'CAL_SELFTEST_ZERO', name: 'no regex fields at all here' };
