420	//    compileDetectGlobal derives the global+case-insensitive variant every matchAll-based
421	//    consumer needs (the distinct-cue counting in facts/sector.js _scoreSectors) from either an
422	//    already-compiled `detect` RegExp (the shipped tree above) or a raw string (a test-injected
423	//    vocabulary, the C-050 dead-regex class); a malformed string throws E_VOCABULARY_BAD_DETECT
424	//    rather than being silently skipped (Rule 4, fail closed).
425	//
426	//    Every SECTORS node's compiled global variant is precomputed ONCE below, before the
427	//    deep-freeze pass, and exposed as a `detectGlobal` sibling alongside the untouched `detect`
428	//    source (so existing vocabulary tests reading `.detect` stay green). facts/sector.js reads
429	//    `detectGlobal` directly for the shipped tree and never constructs a RegExp of its own; this
430	//    function remains the fallback compiler for any vocabulary it is handed at runtime (an
431	//    injected test tree, or a raw string detect).
432	//
433	//    A frozen GLOBAL regex is safe to share and reuse across calls with String.matchAll (the
434	//    spec clones the regex internally and only READS the shared object's lastIndex, which stays
435	//    0 forever on a frozen object); it is NOT safe with .test()/.exec(), which WRITE lastIndex on
436	//    the object itself and throw on a frozen one. facts/sector.js's matchAll-based scorer relies
437	//    on the former; its single `.test()` call site (resolveSubSector) uses the plain, non-global
438	//    `detect` source directly instead, never the global variant.
439	// =================================================================================
440	
441	function compileDetectGlobal(detect) {
442	  if (detect instanceof RegExp) {
443	    const flags = detect.flags.includes('g') ? detect.flags : detect.flags + 'g';
444	    return new RegExp(detect.source, flags.includes('i') ? flags : flags + 'i');
445	  }
446	  if (typeof detect === 'string' && detect) {
447	    try {
448	      return new RegExp(detect, 'gi');
449	    } catch (err) {
450	      const e = new Error(
451	        'facts/vocabulary.js compileDetectGlobal: detect pattern does not compile: '
452	        + JSON.stringify(detect) + ' (' + String(err && err.message) + ')'
453	      );
454	      e.code = 'E_VOCABULARY_BAD_DETECT';
455	      throw e;
456	    }
457	  }
458	  return null;
459	}
460	
461	// Precompile the shipped tree's global variants before the deep-freeze pass at the foot of this
462	// module; never re-compiled at request time.
463	for (const _node of Object.values(SECTORS)) {
464	  if (_node.detect) _node.detectGlobal = compileDetectGlobal(_node.detect);
465	  for (const _sub of Object.values(_node.sub || {})) {
466	    if (_sub.detect) _sub.detectGlobal = compileDetectGlobal(_sub.detect);
467	  }
468	}
